class Solution:
    def abbreviateProduct(self, left: int, right: int) -> str:
        prod = 1
        for x in range(left, right + 1):
            prod *= x
        s = str(prod)
        c = 0
        while s.endswith('0'):
            s = s[:-1]
            c += 1
        if len(s) <= 10:
            return f'{s}e{c}'
        return f'{s[:5]}...{s[-5:]}e{c}'

