function modpow(base, exp, mod) {
    let result = 1n;
    base = base % mod;
    while (exp > 0n) {
        if (exp % 2n === 1n) result = (result * base) % mod;
        exp = exp / 2n;
        base = (base * base) % mod;
    }
    return result;
}

var abbreviateProduct = function(left, right) {
    const mod = 100000000000n;
    let last = 1n;
    let c2 = 0, c5 = 0;
    let digitsSum = 0;
    for (let x = left; x <= right; x++) {
        digitsSum += Math.log10(x);
        let v = x;
        while (v % 2 === 0) { v = Math.floor(v / 2); c2++; }
        while (v % 5 === 0) { v = Math.floor(v / 5); c5++; }
        last = (last * BigInt(v)) % mod;
    }
    const c = Math.min(c2, c5);
    last = (last * modpow(2n, BigInt(c2 - c), mod)) % mod;
    last = (last * modpow(5n, BigInt(c5 - c), mod)) % mod;
    const totalDigits = Math.floor(digitsSum) + 1;
    const prodDigits = totalDigits - c;
    if (prodDigits <= 10) {
        const val = last.toString();
        return `${val}e${c}`;
    }
    const last5 = (last % 100000n).toString().padStart(5, '0');
    const frac = digitsSum - Math.floor(digitsSum);
    const first5 = Math.floor(Math.pow(10, frac + 4)).toString();
    return `${first5}...${last5}e${c}`;
};
